from langchain_core.prompts import PromptTemplate
from langchain_core.runnables import RunnableLambda


def fake_llm(text):
    return f'answer: {text[:40]}'


def build_qa_chain():
    # template expects 'question' but caller passes 'query'
    tmpl = PromptTemplate.from_template('Answer the {question}')
    return tmpl | RunnableLambda(lambda p: fake_llm(p.to_string()))


def answer_question(q):
    chain = build_qa_chain()
    # BUG: template variable mismatch
    return chain.invoke({'query': q})


def main():
    q = 'What is the capital of France?'
    answer = answer_question(q)
    print(answer)


if __name__ == '__main__':
    main()
